// spec-based — <rcu> ещё не реализован компиляторами
#include <rcu>
#include <atomic>
#include <string>
#include <print>

struct Config : std::rcu_obj_base<Config> {
    std::string endpoint;
    int timeout_ms;
};

std::atomic<Config*> current_config{new Config{"localhost", 5000}};

void handle_request() {
    std::rcu_reader reader; // войти в read-side critical section
    Config* cfg = current_config.load(std::memory_order_acquire);
    // cfg гарантированно валиден на протяжении жизни reader
    std::println("connecting to {} with {}ms timeout",
                 cfg->endpoint, cfg->timeout_ms);
    // деструктор reader: выйти из критической секции
}

// spec-based — <rcu> ещё не реализован компиляторами
#include <rcu>
#include <atomic>
#include <string>

struct Config : std::rcu_obj_base<Config> {
    std::string endpoint;
    int timeout_ms;
};

std::atomic<Config*> current_config{new Config{"localhost", 5000}};

void update_config(std::string new_endpoint, int new_timeout) {
    Config* old = current_config.load(std::memory_order_acquire);
    Config* updated = new Config{new_endpoint, new_timeout}; // копия + изменения

    // атомарно публикуем новую версию
    current_config.store(updated, std::memory_order_release);

    // планируем удаление старого конфига после следующего grace period
    // (old может всё ещё использоваться существующими читателями)
    old->retire();
    // retire() не блокирует — писатель возвращается немедленно
    // рантайм вызовет delete old после окончания grace period
}

