#include <atomic>
#include <print>
#include <functional>

std::atomic<bool> done{false};

void call_once_atomic(std::function<void()> fn) {
    bool expected = false;
    if (done.compare_exchange_strong(expected, true,
                                      std::memory_order_acq_rel)) {
        fn();
    }
}

int main() {
    call_once_atomic([]{ std::println("called"); });
    call_once_atomic([]{ std::println("called again"); }); // не должно печатать
    call_once_atomic([]{ std::println("called third"); }); // не должно печатать
}
